class DiskCacheSystem {
    private final String cacheDirectory;
    private final ConcurrentHashMap<String, CacheEntry> memoryCache;
    private final long defaultTTL;

    public DiskCacheSystem(String cacheDirectory, long defaultTTL) {
        this.cacheDirectory = cacheDirectory;
        this.memoryCache = new ConcurrentHashMap<>();
        this.defaultTTL = defaultTTL;
        
        try {
            Files.createDirectories(Paths.get(cacheDirectory));
        } catch (IOException e) {
            throw new RuntimeException("Failed to create cache directory", e);
        }
    }

    public DiskCacheSystem(String cacheDirectory) {
        this(cacheDirectory, 3600000);
    }

    private String getCacheFilePath(String key) {
        String safeKey = key.replaceAll("[^a-zA-Z0-9.-]", "_");
        return cacheDirectory + File.separator + safeKey + ".cache";
    }

    public void put(String key, Object value) {
        put(key, value, defaultTTL);
    }

    public void put(String key, Object value, long ttl) {
        CacheEntry entry = new CacheEntry(value, ttl);
        memoryCache.put(key, entry);
        saveToDisk(key, entry);
    }

    private void saveToDisk(String key, CacheEntry entry) {
        String filePath = getCacheFilePath(key);
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new BufferedOutputStream(new FileOutputStream(filePath)))) {
            oos.writeObject(entry);
        } catch (IOException e) {
            System.err.println("Failed to save cache entry to disk: " + e.getMessage());
        }
    }

    public Object get(String key) {
        CacheEntry entry = memoryCache.get(key);
        
        if (entry != null) {
            if (entry.isExpired()) {
                invalidate(key);
                return null;
            }
            return entry.getValue();
        }

        entry = loadFromDisk(key);
        if (entry != null) {
            if (entry.isExpired()) {
                invalidate(key);
                return null;
            }
            memoryCache.put(key, entry);
            return entry.getValue();
        }

        return null;
    }

    private CacheEntry loadFromDisk(String key) {
        String filePath = getCacheFilePath(key);
        File file = new File(filePath);
        
        if (!file.exists()) {
            return null;
        }

        try (ObjectInputStream ois = new ObjectInputStream(
                new BufferedInputStream(new FileInputStream(filePath)))) {
            return (CacheEntry) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Failed to load cache entry from disk: " + e.getMessage());
            return null;
        }
    }

    public void invalidate(String key) {
        memoryCache.remove(key);
        String filePath = getCacheFilePath(key);
        try {
            Files.deleteIfExists(Paths.get(filePath));
        } catch (IOException e) {
            System.err.println("Failed to delete cache file: " + e.getMessage());
        }
    }

    public void clear() {
        memoryCache.clear();
        try {
            Files.walk(Paths.get(cacheDirectory))
                    .filter(Files::isRegularFile)
                    .filter(path -> path.toString().endsWith(".cache"))
                    .forEach(path -> {
                        try {
                            Files.delete(path);
                        } catch (IOException e) {
                            System.err.println("Failed to delete cache file: " + e.getMessage());
                        }
                    });
        } catch (IOException e) {
            System.err.println("Failed to clear cache: " + e.getMessage());
        }
    }

    public boolean containsKey(String key) {
        if (memoryCache.containsKey(key)) {
            CacheEntry entry = memoryCache.get(key);
            if (!entry.isExpired()) {
                return true;
            }
            invalidate(key);
            return false;
        }

        String filePath = getCacheFilePath(key);
        if (new File(filePath).exists()) {
            CacheEntry entry = loadFromDisk(key);
            if (entry != null && !entry.isExpired()) {
                memoryCache.put(key, entry);
                return true;
            }
            invalidate(key);
        }
        return false;
    }

    public Set<String> getAllKeys() {
        Set<String> keys = new HashSet<>(memoryCache.keySet());
        try {
            Files.walk(Paths.get(cacheDirectory))
                    .filter(Files::isRegularFile)
                    .filter(path -> path.toString().endsWith(".cache"))
                    .forEach(path -> {
                        String fileName = path.getFileName().toString();
                        String key = fileName.substring(0, fileName.length() - 6);
                        keys.add(key);
                    });
        } catch (IOException e) {
            System.err.println("Failed to list cache keys: " + e.getMessage());
        }
        return keys;
    }

    public long getCacheSize() {
        try {
            return Files.walk(Paths.get(cacheDirectory))
                    .filter(Files::isRegularFile)
                    .filter(path -> path.toString().endsWith(".cache"))
                    .mapToLong(path -> {
                        try {
                            return Files.size(path);
                        } catch (IOException e) {
                            return 0;
                        }
                    })
                    .sum();
        } catch (IOException e) {
            System.err.println("Failed to calculate cache size: " + e.getMessage());
            return 0;
        }
    }

    public void cleanupExpired() {
        Set<String> allKeys = getAllKeys();
        for (String key : allKeys) {
            CacheEntry entry = loadFromDisk(key);
            if (entry != null && entry.isExpired()) {
                invalidate(key);
            }
        }
        
        memoryCache.entrySet().removeIf(entry -> entry.getValue().isExpired());
    }
}

